import { useState, useEffect, useCallback } from "react";
import { PublicKey } from "@solana/web3.js";
import { getReadOnlyProgram, getConnection } from "../lib/program";
import {
  PROPERTIES,
  getPropertyPDA,
  getMintPDA,
  getVaultPDA,
  lamportsToSol,
  formatIDR,
  IDR_PER_SOL,
